from typing import List

class BookMyShow:

    def __init__(self, n: int, m: int):
        self.n = n
        self.m = m
        self.rows = [[0]*m for _ in range(n)]
        self.prefix_sum = [[0]*(m+1) for _ in range(n)]

    def gather(self, k: int, maxRow: int) -> List[int]:
        for i in range(min(maxRow+1, self.n)):
            if self.prefix_sum[i][self.m] - self.prefix_sum[i][0] >= k:
                for j in range(self.m-k+1):
                    if self.prefix_sum[i][j+k] - self.prefix_sum[i][j] == 0:
                        for x in range(j, j+k):
                            self.rows[i][x] = 1
                            self.prefix_sum[i][x+1] += 1
                        return [i, j]
        return []

    def scatter(self, k: int, maxRow: int) -> bool:
        remaining_seats = 0
        for i in range(min(maxRow+1, self.n)):
            remaining_seats += self.m - (self.prefix_sum[i][self.m] - self.prefix_sum[i][0])
        if remaining_seats < k:
            return False
        for i in range(min(maxRow+1, self.n)):
            available_seats = self.m - (self.prefix_sum[i][self.m] - self.prefix_sum[i][0])
            seats_to_allocate = min(k, available_seats)
            for j in range(seats_to_allocate):
                self.rows[i][self.prefix_sum[i][self.m] - self.prefix_sum[i][0] + j] = 1
                self.prefix_sum[i][self.prefix_sum[i][self.m] - self.prefix_sum[i][0] + j + 1] += 1
            k -= seats_to_allocate
            if k == 0:
                break
        return True


